### 4. gRPC 서비스 정의 (Proto)

**위치**: `protobuf/src/main/proto/chat/chat_service.proto`

```protobuf
syntax = "proto3";
package chat;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.chat";

service ChatService {
  rpc CreateChatRoom(CreateChatRoomRequest) returns (CreateChatRoomResponse);
  rpc GetChatRoom(GetChatRoomRequest) returns (GetChatRoomResponse);
  rpc ListChatRooms(ListChatRoomsRequest) returns (ListChatRoomsResponse);

  rpc SendMessage(SendMessageRequest) returns (SendMessageResponse);
  rpc GetMessages(GetMessagesRequest) returns (GetMessagesResponse);
  rpc DeleteMessage(DeleteMessageRequest) returns (DeleteMessageResponse);

  rpc AddParticipant(AddParticipantRequest) returns (AddParticipantResponse);
  rpc RemoveParticipant(RemoveParticipantRequest) returns (RemoveParticipantResponse);
  rpc ListParticipants(ListParticipantsRequest) returns (ListParticipantsResponse);

  rpc MarkAsRead(MarkAsReadRequest) returns (MarkAsReadResponse);
}

message CreateChatRoomRequest {
  string creator_user_id = 1;
  string name = 2;
  int32 room_type = 3;        // DIRECT=0, GROUP=1
  repeated string participant_user_ids = 4;
  int32 max_participants = 5;
}

message CreateChatRoomResponse {
  ChatRoom chat_room = 1;
}

message ChatRoom {
  string id = 1;
  string name = 2;
  int32 room_type = 3;
  string creator_user_id = 4;
  int32 participant_count = 5;
  string created_at = 6;
  string updated_at = 7;
}

message SendMessageRequest {
  string room_id = 1;
  string sender_user_id = 2;
  int32 message_type = 3;     // TEXT=0, IMAGE=1, FILE=2, VOICE=3
  string content = 4;
  string file_url = 5;
}

message SendMessageResponse {
  ChatMessage message = 1;
}

message ChatMessage {
  string id = 1;
  string room_id = 2;
  string sender_user_id = 3;
  int32 message_type = 4;
  string content = 5;
  string file_url = 6;
  string created_at = 7;
}

message GetMessagesRequest {
  string room_id = 1;
  int32 limit = 2;
  int32 offset = 3;
  string before_message_id = 4;  // 페이지네이션
}

message GetMessagesResponse {
  repeated ChatMessage messages = 1;
  int32 total_count = 2;
}

message MarkAsReadRequest {
  string room_id = 1;
  string user_id = 2;
  string last_read_message_id = 3;
}

message MarkAsReadResponse {
  bool success = 1;
}

message AddParticipantRequest {
  string room_id = 1;
  string user_id = 2;
  int32 role = 3;  // MEMBER=0, ADMIN=1
}

message AddParticipantResponse {
  ChatParticipant participant = 1;
}

message ChatParticipant {
  string id = 1;
  string room_id = 2;
  string user_id = 3;
  int32 role = 4;
  string created_at = 5;
}
```

