### 5. GraphQL 스키마

**위치**: `graphql/src/main/resources/graphql/chat.graphqls`

```graphql
type ChatRoom {
  id: ID!
  name: String!
  roomType: ChatRoomType!
  creatorUser: SimpleUser!
  participantCount: Int!
  participants: [ChatParticipant!]!
  latestMessage: ChatMessage
  unreadCount: Int!
  createdAt: String!
  updatedAt: String!
}

type ChatMessage {
  id: ID!
  roomId: ID!
  senderUser: SimpleUser!
  messageType: ChatMessageType!
  content: String!
  fileUrl: String
  createdAt: String!
  updatedAt: String!
  isDeleted: Boolean!
}

type ChatParticipant {
  id: ID!
  roomId: ID!
  user: SimpleUser!
  role: ParticipantRole!
  lastReadMessageId: String
  lastReadAt: String
  createdAt: String!
}

enum ChatRoomType {
  DIRECT
  GROUP
}

enum ChatMessageType {
  TEXT
  IMAGE
  FILE
  VOICE
}

enum ParticipantRole {
  MEMBER
  ADMIN
}

input CreateChatRoomInput {
  name: String!
  roomType: ChatRoomType!
  participantUserIds: [String!]!
  maxParticipants: Int
}

input SendChatMessageInput {
  roomId: ID!
  messageType: ChatMessageType!
  content: String!
  fileUrl: String
}

input MarkAsReadInput {
  roomId: ID!
  lastReadMessageId: ID!
}

extend type Query {
  chatRoom(id: ID!): ChatRoom!
  chatRooms(limit: Int, offset: Int): [ChatRoom!]!
  chatMessages(roomId: ID!, limit: Int, offset: Int): [ChatMessage!]!
}

extend type Mutation {
  createChatRoom(input: CreateChatRoomInput!): ChatRoom!
  sendChatMessage(input: SendChatMessageInput!): ChatMessage!
  deleteChatMessage(messageId: ID!): Boolean!
  markAsRead(input: MarkAsReadInput!): Boolean!
  addParticipant(roomId: ID!, userId: String!): ChatParticipant!
  removeParticipant(roomId: ID!, userId: String!): Boolean!
}

type SimpleUser {
  id: ID!
  nickname: String!
  profileImageUrl: String
}
```

